extension ModelMacro {
  static func generateMetadataSlot(
    access         : String,
    modelClassName : TokenSyntax,
    properties     : [ ModelProperty ]
  ) -> DeclSyntax
  {
    func generateInfo(for property: ModelProperty) -> ExprSyntax? {
      guard let valueType = property.valueType     else { return nil }
      guard valueType.isKnownAttributePropertyType else { return nil }
      let cleanValueType = valueType.replacingImplicitlyUnwrappedOptionalTypes().trimmed
      return "CoreData.NSAttributeDescription(name: \(literal: property.name), valueType: \(cleanValueType).self)"
    }
    func attributeInfo(for property: ModelProperty,
                       attribute syntax: AttributeSyntax)
         -> ExprSyntax?
    {
      let valueType : TypeSyntax = property.valueType?
        .replacingImplicitlyUnwrappedOptionalTypes().trimmed ?? "Any"
      var fallback: ExprSyntax {
        "CoreData.NSAttributeDescription(name: \(literal: property.name), valueType: \(valueType).self)"
      }
      guard let arguments = syntax.arguments else { return fallback }
      guard case .argumentList(var labeledExpressions) = arguments else {
        return fallback
      }
      labeledExpressions.append(.init(
        label: "name", expression: ExprSyntax("\(literal: property.name)")
      ))
      labeledExpressions.append(.init(
        label: "valueType", expression: ExprSyntax("\(valueType).self")
      ))
      return ExprSyntax(FunctionCallExprSyntax(callee: ExprSyntax("CoreData.NSAttributeDescription")) {
        labeledExpressions
      })
    }
    func relationshipInfo(for property: ModelProperty,
                          attribute syntax: AttributeSyntax) -> ExprSyntax?
    {
      let valueType : TypeSyntax = property.valueType?
        .replacingImplicitlyUnwrappedOptionalTypes().trimmed ?? "Any"
      var fallback: ExprSyntax {
        "CoreData.NSRelationshipDescription(name: \(literal: property.name), valueType: \(valueType).self)"
      }
      guard let arguments = syntax.arguments else { return fallback }
      guard case .argumentList(var labeledExpressions) = arguments else {
        return fallback
      }
      labeledExpressions.append(.init(
        label: "name", expression: ExprSyntax("\(literal: property.name)")
      ))
      labeledExpressions.append(.init(
        label: "valueType", expression: ExprSyntax("\(valueType).self")
      ))
      return ExprSyntax(FunctionCallExprSyntax(callee: ExprSyntax("CoreData.NSRelationshipDescription")) {
        labeledExpressions
      })
    }
    func metadata(for property: ModelProperty) -> ExprSyntax {
      let metaExpr : ExprSyntax? = switch property.type {
        case .plain: generateInfo(for: property)
        case .attribute   (let attribute, isTransformable: _):
          attributeInfo   (for: property, attribute: attribute)
        case .relationship(let attribute):
          relationshipInfo(for: property, attribute: attribute)
      }
      let initExpr = property.initExpression ?? "nil"
      return """
      .init(name: \(literal: property.name), keypath: \\\(raw: modelClassName.trimmed).\(raw: property.name),
            defaultValue: \(initExpr),
            metadata: \(metaExpr ?? "nil"))
      """
    }
    let fields = ArrayExprSyntax(expressions: properties
      .filter({ !$0.isTransient})
      .map(metadata(for:))
    )
    return
      """
      \(raw: access)static let schemaMetadata : [ CoreData.NSManagedObjectModel.PropertyMetadata ] = \(fields)
      """
  }
}

extension ModelMacro: ExtensionMacro { // @attached(extension, conformances:..)
  /*
   @attached(extension, conformances: // the protocols we add automagically
     PersistentModel
   )
   */
  public static func expansion(
    of               macroNode : AttributeSyntax,
    attachedTo     declaration : some DeclGroupSyntax,    // the class
    providingExtensionsOf type : some TypeSyntaxProtocol, // the classtype
    conformingTo conformancesToAdd : [ TypeSyntax ],
    in                 context : some MacroExpansionContext
  ) throws -> [ ExtensionDeclSyntax ]
  {
    guard let classDecl = declaration.as(ClassDeclSyntax.self) else {
      context.diagnose(.modelMacroCanOnlyBeAppliedOnNSManagedObjects,
                       on: macroNode)
      return [] // TBD: rather throw?
    }
    let inheritedTypeNames = classDecl.inheritedTypeNames
    guard inheritedTypeNames.contains("NSManagedObject") ||
          inheritedTypeNames.contains("CoreData.NSManagedObject") else
    {
      context.diagnose(.modelMacroCanOnlyBeAppliedOnNSManagedObjects,
                       on: macroNode)
      return [] // TBD: rather throw?
    }
    guard !inheritedTypeNames.contains("PersistentModel") &&
          !inheritedTypeNames.contains("ManagedModels.PersistentModel") else
    {
      return []
    }
    if !conformancesToAdd.isEmpty { // this isn't always filled?
      var stillNeeded = false
      for conformance in conformancesToAdd {
        guard let id = conformance.as(IdentifierTypeSyntax.self) else {
          assertionFailure("Unexpected conformance? \(conformance)")
          continue
        }
        let name = id.name.trimmed.text
        if name == "PersistentModel" || 
           name == "ManagedModels.PersistentModel"
        {
          stillNeeded = true
        }
        else {
          assertionFailure("Unexpected conformance: \(name)")
        }
      }
      guard stillNeeded else { return [] }
    }
    return [
      try ExtensionDeclSyntax(
        "extension \(type): ManagedModels.PersistentModel"
      ) {}
    ]
  }
}

extension ModelMacro: MemberAttributeMacro { // @attached(memberAttribute)
  public static func expansion(
    of                   macroNode : AttributeSyntax,
    attachedTo         declaration : some DeclGroupSyntax,
    providingAttributesFor  member : some DeclSyntaxProtocol,
    in                     context : some MacroExpansionContext
  ) throws -> [ AttributeSyntax ]
  {
    guard declaration.is(ClassDeclSyntax.self) else {
      context.diagnose(.modelMacroCanOnlyBeAppliedOnNSManagedObjects,
                       on: macroNode)
      return [] // TBD: rather throw?
    }
    var properties = [ ModelProperty ]()
    addModelProperties(in: member, to: &properties,
                       context: context)
    guard let property = properties.first else { return [] } // other member
    if properties.count > 1 {
      context.diagnose(.multipleMembersInAttributesMacroCall, on: macroNode)
      return []
    }
    guard !property.isTransient else { return [] }
    /*
     var firstname = "Jason"
     var lastname  : String
     */
    let isRelationship: Bool
    if case .relationship(_) = property.type {
      isRelationship = true
    } else {
      isRelationship = false
    }
    let addAtObjC = isRelationship
                 || (property.valueType?.canBeRepresentedInObjectiveC ?? false)
    return addAtObjC
         ? [ "@_PersistedProperty", "@objc" ]
         : [ "@_PersistedProperty" ]
  }
}

extension ModelMacro: MemberMacro { // @attached(member, names:...)
  public static func expansion(
    of                   macroNode : AttributeSyntax,
    providingMembersOf declaration : some DeclGroupSyntax,
    conformingTo         protocols : [ TypeSyntax ],
    in                     context : some MacroExpansionContext
  ) throws -> [ DeclSyntax ]
  {
    guard let classDecl = declaration.as(ClassDeclSyntax.self) else {
      context.diagnose(.modelMacroCanOnlyBeAppliedOnNSManagedObjects,
                       on: macroNode)
      return [] // TBD: rather throw?
    }
    let modelClassName = classDecl.name.trimmed
    let properties = findModelProperties(in: classDecl,
                                         errorNode: macroNode, context: context)
    let access = classDecl.isPublicOrOpen ? "public " : ""
    var newMembers = generateInitializers(
      for: classDecl,
      access: access, modelClassName: modelClassName,
      properties: properties,
      initializers: findInitializers(in: classDecl)
    )
    let metadata = generateMetadataSlot(
      access: access,
      modelClassName: modelClassName,
      properties: properties
    )
    newMembers.append(DeclSyntax(metadata))
    newMembers.append(
      """
      \(raw: access)static let _$originalName : String? = nil
      """
    )
    newMembers.append(
      """
      \(raw: access)static let _$hashModifier : String? = nil
      """
    )
    return newMembers
  }
}

extension ModelMacro {
  static func findInitializers(in classDecl: ClassDeclSyntax)
              -> [ ModelInitializer ]
  {
    var initializers = [ ModelInitializer ]()
    for member : MemberBlockItemSyntax in classDecl.memberBlock.members {
      guard let initDecl = member.decl.as(InitializerDeclSyntax.self) else {
        continue
      }
      var numberOfParametersWithoutDefaults = 0
      var keywords = [ String ]()
      for parameter : FunctionParameterSyntax
            in initDecl.signature.parameterClause.parameters
      {
        if parameter.firstName.tokenKind == .wildcard { keywords.append("") }
        else { keywords.append(parameter.firstName.trimmedDescription) }
        if parameter.defaultValue == nil {
          numberOfParametersWithoutDefaults += 1
        }
      }
      initializers.append(ModelInitializer(
        isConvenience: initDecl.isConvenience,
        parameterKeywords: keywords,
        numberOfParametersWithoutDefaults: numberOfParametersWithoutDefaults
      ))
    }
    return initializers
  }
}

struct ModelProperty {
  /**
   * Whether the property is an attribute or relationship,
   * or whether it is unknown at macro expansion time.
   */
  enum PropertyType {
    /// The property had no `@Relationship` or `@Attribute` marker macros.
    case plain
    /// The property was explicitly tagged as a `Relationship`.
    case relationship(AttributeSyntax)
    /// The property was explicitly tagged as an `Attribute`.
    case attribute   (AttributeSyntax, isTransformable: Bool)
  }
  let binding           : PatternBindingSyntax
  let type              : PropertyType
  let name              : String
  let declaredValueType : TypeSyntax?
  let isTransient       : Bool
  let initExpression    : ExprSyntax?
}

extension ModelProperty {
  /**
   * If the property type was not declared, attempt to derive the type from
   * expression.
   *
   * Example:
   * ```
   * var lastname = "Street"
   * ```
   * => type will be `String`, because it is a String literal initializer.
   */
  var valueType: TypeSyntax? {
    if let declaredValueType { return declaredValueType }
    guard let initExpression else { return nil }
    return initExpression.detectExpressionType()
  }
  var isKnownAttributePropertyType: Bool {
    switch type {
      case .attribute(_, _) : return true
      case .relationship(_) : return false
      case .plain: return valueType?.isKnownAttributePropertyType ?? false
    }
  }
  var isKnownRelationshipPropertyType: Bool {
    switch type {
      case .attribute(_, _) : return false
      case .relationship(_) : return true
      case .plain: return valueType?.isKnownRelationshipPropertyType ?? false
    }
  }
}

extension ModelMacro {
  static func findModelProperties(in classDecl: ClassDeclSyntax,
                                  errorNode: AttributeSyntax,
                                  context: some MacroExpansionContext)
              -> [ ModelProperty ]
  {
    var properties = [ ModelProperty ]()
    for member : MemberBlockItemSyntax in classDecl.memberBlock.members {
      addModelProperties(in: member.decl, to: &properties,
                         context: context)
    }
    return properties
  }
  /**
   * This creates a `ModelProperty` object/value for each property in the
   * given `VariableDeclSyntax`.
   *
   * A variable decl is something like this:
   * ```swift
   * @Relationship(inverse: \.blub)
   * var street, city, country : String
   * ```
   * Note that attributes (e.g. `@Relationship` is one) are attached to the
   * whole declaration, but the declaration can have multiple "bindings",
   * i.e. properties.
   *
   * It uses the `propertyType` function below to look for the attributes.
   */
  static func addModelProperties<T>(in member: T,
                                    to properties: inout [ ModelProperty ],
                                    context: some MacroExpansionContext)
    where T: SyntaxProtocol
  {
    guard let variables = member.as(VariableDeclSyntax.self) else {
      return
    }
    guard !variables.isStaticOrClass else { return }
    let ( propertyType, isTransient ) = propertyType(
      for: variables.attributes, context: context
    )
    for binding : PatternBindingSyntax in variables.bindings {
      guard binding.accessorBlock == nil else {
        continue
      }
      guard let pattern = binding.pattern.as(IdentifierPatternSyntax.self) else
      {
        continue
      }
      let name = pattern.identifier.trimmed.text
      guard !forbiddenPropertyNames.contains(name) else {
        context.diagnose(.propertyNameIsForbidden,
                         on: member)
        continue
      }
      properties.append(ModelProperty(
        binding: binding,
        type: propertyType,
        name: name,
        declaredValueType: binding.typeAnnotation?.type, // w/o the `:`
        isTransient: isTransient,
        initExpression: binding.initializer?.value // w/o the `=`
      ))
    }
  }
  private static func propertyType(
    for attributes: AttributeListSyntax,
    context: some MacroExpansionContext
  ) -> ( propertyType : ModelProperty.PropertyType, isTransient: Bool )
  {
    var propertyType = ModelProperty.PropertyType.plain
    var isTransient  = false
    for attribute : AttributeListSyntax.Element in attributes {
      switch attribute {
        case .ifConfigDecl(_):
          continue
        case .attribute(let attribute):
          guard let name = attribute
            .attributeName.as(IdentifierTypeSyntax.self)?
            .name.trimmed.text else
          {
            continue
          }
          switch name {
            case "Transient":
              assert(!isTransient, "Transient macro applied twice!")
              isTransient = true
            case "Attribute":
              switch propertyType {
                case .plain:
                  propertyType = .attribute(
                    attribute,
                    isTransformable: isTransformableAttribute(attribute)
                  )
                case .attribute(_, _):
                  context.diagnose(.multipleAttributeMacrosAppliedOnProperty,
                                   on: attributes)
                case .relationship(_):
                  context.diagnose(
                    .attributeAndRelationshipMacrosAppliedOnProperty,
                    on: attributes
                  )
              }
            case "Relationship":
              switch propertyType {
                case .plain:
                  propertyType = .relationship(attribute)
                case .relationship(_):
                  context.diagnose(
                    .multipleRelationshipMacrosAppliedOnProperty,
                    on: attributes
                  )
                case .attribute(_, _):
                  context.diagnose(
                    .attributeAndRelationshipMacrosAppliedOnProperty,
                    on: attributes
                  )
              }
            default:
              break
          }
      }
    }
    return ( propertyType, isTransient )
  }
  private static func isTransformableAttribute(_ syntax: AttributeSyntax)
                      -> Bool
  {
    guard let arguments = syntax.arguments,
          case .argumentList(let labeledExpressions) = arguments else
    {
      return false
    }
    for labeledExpression in labeledExpressions {
      guard labeledExpression.label == nil else { break }
      guard let funCall = labeledExpression.expression
                            .as(FunctionCallExprSyntax.self),
            let member = funCall.calledExpression
                            .as(MemberAccessExprSyntax.self)
      else {
        continue
      }
      guard case .identifier(let name) =
              member.declName.baseName.tokenKind else
      {
        continue
      }
      if name == "transformable" { return true }
    }
    return false
  }
}
